'use client'

import {
  cn,
  DismissableLayer,
  FocusScope,
  Portal,
  Presence,
  useControllableSignal,
  useDraggable,
  useScrollLock,
  useSignals,
} from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import { useId } from 'react'
import type { CSSProperties, ReactNode, Ref } from 'react'
import styles from './drawer.module.css'

/** Drag distance (px) past which a swipe dismisses the drawer. */
const SWIPE_DISMISS_THRESHOLD = 80

export interface DrawerProps {
  /** Controlled open state. */
  open?: boolean
  /** Initial open state for uncontrolled use. */
  defaultOpen?: boolean
  /** Called whenever the open state should change. */
  onOpenChange?: (open: boolean) => void
  /** Edge the panel is anchored to. Drives the slide direction. */
  side?: 'start' | 'end' | 'top' | 'bottom'
  /** Panel size along its cross axis (width for start/end, height for top/bottom). */
  size?: string
  /** Accessible title shown in the header and used to label the dialog. */
  title?: ReactNode
  /** Optional supporting description shown under the title. */
  description?: ReactNode
  children?: ReactNode
  labels?: { close?: string }
  className?: string
  /** Allow dragging the header toward its edge to dismiss (opt-in; CSS translate, no animation library). */
  swipeToDismiss?: boolean
}

/**
 * Edge-anchored panel. Unlike Sheet's gesture-driven sheet, Drawer is a plain dialog surface that
 * slides in from an edge with CSS-only enter/exit motion (data-state + @starting-style). Open state
 * is controllable; while open, body scroll is locked, focus is trapped, and outside pointer /
 * Escape dismiss it.
 */
export function Drawer({
  open,
  defaultOpen,
  onOpenChange,
  side = 'end',
  size,
  title,
  description,
  children,
  labels,
  className,
  swipeToDismiss = false,
}: DrawerProps) {
  useSignals()
  const [isOpen, setOpen] = useControllableSignal<boolean>({
    value: open,
    defaultValue: defaultOpen ?? false,
    onChange: onOpenChange,
  })

  useScrollLock(isOpen)

  // Drag-to-dismiss: constrain to the panel's edge axis; past a threshold in the
  // dismiss direction, close via the existing onOpenChange path; otherwise snap back.
  const dragAxis = side === 'top' || side === 'bottom' ? 'y' : 'x'
  const { handleRef, offset, isDragging, reset } = useDraggable({
    isDisabled: !swipeToDismiss,
    axis: dragAxis,
    onDragEnd: (o) => {
      const dist = dragAxis === 'y' ? o.y : o.x
      const dismiss =
        (side === 'end' && dist > SWIPE_DISMISS_THRESHOLD) ||
        (side === 'start' && dist < -SWIPE_DISMISS_THRESHOLD) ||
        (side === 'bottom' && dist > SWIPE_DISMISS_THRESHOLD) ||
        (side === 'top' && dist < -SWIPE_DISMISS_THRESHOLD)
      reset()
      if (dismiss) setOpen(false)
    },
  })

  const titleId = useId()
  const descId = useId()
  const closeLabel = labels?.close ?? t(builtin.drawer.close)

  const panelStyle: CSSProperties = {
    ...(size ? { '--_drawer-size': size } : {}),
    ...(swipeToDismiss
      ? { '--_drawer-drag-x': `${offset.value.x}px`, '--_drawer-drag-y': `${offset.value.y}px` }
      : {}),
  } as CSSProperties

  return (
    <Portal>
      <Presence present={isOpen}>
        <div className={styles['overlay']} data-side={side}>
          <DismissableLayer onDismiss={() => setOpen(false)}>
            <FocusScope trapped restoreFocus autoFocus>
              <div
                role="dialog"
                aria-modal="true"
                aria-labelledby={title ? titleId : undefined}
                aria-describedby={description ? descId : undefined}
                data-side={side}
                data-dragging={swipeToDismiss && isDragging.value ? '' : undefined}
                className={cn(styles['panel'], className)}
                style={panelStyle}
              >
                {(title || description) && (
                  <div
                    className={styles['header']}
                    ref={swipeToDismiss ? (handleRef as Ref<HTMLDivElement>) : undefined}
                  >
                    <div className={styles['heading']}>
                      {title && (
                        <h2 id={titleId} className={styles['title']}>
                          {title}
                        </h2>
                      )}
                      {description && (
                        <p id={descId} className={styles['description']}>
                          {description}
                        </p>
                      )}
                    </div>
                    <button
                      type="button"
                      aria-label={closeLabel}
                      onClick={() => setOpen(false)}
                      className={styles['close']}
                    >
                      <svg aria-hidden="true" viewBox="0 0 16 16" className={styles['closeIcon']}>
                        <path
                          d="M4 4l8 8M12 4l-8 8"
                          fill="none"
                          stroke="currentColor"
                          strokeWidth="1.5"
                          strokeLinecap="round"
                        />
                      </svg>
                    </button>
                  </div>
                )}
                <div className={styles['body']}>{children}</div>
              </div>
            </FocusScope>
          </DismissableLayer>
        </div>
      </Presence>
    </Portal>
  )
}

@layer cascivo.component {
  .overlay {
    position: fixed;
    inset: 0;
    z-index: var(--cascivo-z-overlay, 50);
    display: flex;
    background-color: rgb(0 0 0 / 0.4);
    opacity: 1;
    transition: opacity var(--cascivo-motion-enter);

    &[data-state='closed'] {
      opacity: 0;
      transition: opacity var(--cascivo-motion-exit);
    }

    @starting-style {
      &[data-state='open'] {
        opacity: 0;
      }
    }

    /* Anchor the panel to the requested edge. */
    &[data-side='end'] {
      justify-content: flex-end;
      align-items: stretch;
    }
    &[data-side='start'] {
      justify-content: flex-start;
      align-items: stretch;
    }
    &[data-side='top'] {
      align-items: flex-start;
    }
    &[data-side='bottom'] {
      align-items: flex-end;
    }
  }

  .panel {
    display: flex;
    flex-direction: column;
    background: var(--cascivo-color-surface);
    box-shadow: var(--cascivo-shadow-overlay);
    /* `translate` drives the slide in/out; `transform` carries the drag offset so
       the two compose without fighting. */
    transform: none; /* static fallback */
    transform: translate(var(--_drawer-drag-x, 0), var(--_drawer-drag-y, 0));
    transition:
      translate var(--cascivo-motion-enter),
      transform var(--cascivo-motion-exit);

    /* While dragging, follow the pointer with no transition lag. */
    &[data-dragging] {
      transition: none;
    }

    .overlay[data-state='closed'] & {
      transition: translate var(--cascivo-motion-exit);
    }

    &[data-side='end'] {
      inline-size: var(--_drawer-size, min(24rem, 90vw));
      block-size: 100%;
      border-inline-start: 1px solid var(--cascivo-color-border);
      border-radius: var(--cascivo-radius-overlay) 0 0 var(--cascivo-radius-overlay);
      translate: 0 0;
    }
    .overlay[data-state='closed'] &[data-side='end'] {
      translate: 100% 0;
    }

    &[data-side='start'] {
      inline-size: var(--_drawer-size, min(24rem, 90vw));
      block-size: 100%;
      border-inline-end: 1px solid var(--cascivo-color-border);
      border-radius: 0 var(--cascivo-radius-overlay) var(--cascivo-radius-overlay) 0;
      translate: 0 0;
    }
    .overlay[data-state='closed'] &[data-side='start'] {
      translate: -100% 0;
    }

    &[data-side='top'] {
      inline-size: 100%;
      block-size: var(--_drawer-size, auto);
      max-block-size: 80vh;
      border-block-end: 1px solid var(--cascivo-color-border);
      border-radius: 0 0 var(--cascivo-radius-overlay) var(--cascivo-radius-overlay);
      translate: 0 0;
    }
    .overlay[data-state='closed'] &[data-side='top'] {
      translate: 0 -100%;
    }

    &[data-side='bottom'] {
      inline-size: 100%;
      block-size: var(--_drawer-size, auto);
      max-block-size: 80vh;
      border-block-start: 1px solid var(--cascivo-color-border);
      border-radius: var(--cascivo-radius-overlay) var(--cascivo-radius-overlay) 0 0;
      translate: 0 0;
    }
    .overlay[data-state='closed'] &[data-side='bottom'] {
      translate: 0 100%;
    }
  }

  /* Enter from off-screen on first mount. */
  @starting-style {
    .overlay[data-state='open'] .panel[data-side='end'] {
      translate: 100% 0;
    }
    .overlay[data-state='open'] .panel[data-side='start'] {
      translate: -100% 0;
    }
    .overlay[data-state='open'] .panel[data-side='top'] {
      translate: 0 -100%;
    }
    .overlay[data-state='open'] .panel[data-side='bottom'] {
      translate: 0 100%;
    }
  }

  .header {
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: var(--cascivo-space-4);
    padding: var(--cascivo-space-4) var(--cascivo-space-6);
    border-block-end: 1px solid var(--cascivo-color-border);
    flex-shrink: 0;
  }

  .heading {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-1);
  }

  .title {
    margin: 0;
    font-size: var(--cascivo-text-lg);
    font-weight: var(--cascivo-font-semibold);
    color: var(--cascivo-color-text);
  }

  .description {
    margin: 0;
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text-subtle);
  }

  .close {
    display: flex;
    align-items: center;
    justify-content: center;
    inline-size: 2rem;
    block-size: 2rem;
    padding: 0;
    color: var(--cascivo-color-text-muted);
    background: transparent;
    border: none;
    border-radius: var(--cascivo-radius-control);
    cursor: pointer;
    flex-shrink: 0;
    transition:
      color var(--cascivo-duration-150) var(--cascivo-ease-out),
      background-color var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover {
      color: var(--cascivo-color-text);
      background-color: var(--cascivo-color-bg-subtle);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }
  }

  .closeIcon {
    inline-size: 1rem;
    block-size: 1rem;
  }

  .body {
    padding: var(--cascivo-space-6);
    overflow-y: auto;
    flex: 1;
  }

  @media (prefers-reduced-motion: reduce) {
    .panel {
      transition: none;
    }
  }
}
